import ast, base64, pathlib

TARGET = pathlib.Path("modules/net/scan.py")
MAIN = base64.b64decode("").decode()

src = TARGET.read_text(encoding="utf-8")
lines = src.splitlines()
cut = next((i for i, ln in enumerate(lines)
            if ln.startswith("def main(")), None)
if cut is not None:
    while cut > 0 and lines[cut - 1].strip() == "":
        cut -= 1
    lines = lines[:cut]
clean = "\n".join(lines).rstrip("\n")
new = clean + "\n\n\n" + MAIN
ast.parse(new)
TARGET.write_text(new, encoding="utf-8")
print("scan.py: main() replaced with name-agnostic version")

